def _resolve_lifetime_trades(strategy_name: str, today_stats: dict, state: dict) -> int:
    """Authoritative lifetime trade count for SILENT-strategy check.

    today_stats.by_strategy is empty on weekends (no trades in 24h window),
    causing _flag_silent_strategies to false-positive SILENT for strategies
    with real lifetime trades in state.json.
    Confirmed case 2026-05-24: options-momentum trades_lifetime=1 in state.json
    but by_strategy={} -> SILENT fires incorrectly.

    Returns max(state_count, today_count). Operator wires into
    _flag_silent_strategies lines 287-288: replace
      stats = by_strat.get(name) or {}
      if stats.get('trades_lifetime', 0) > 0:
    with:
      if _resolve_lifetime_trades(name, today_stats, state) > 0:
    """
    state_count = (state.get("strategies") or {}).get(strategy_name, {}).get("trades_lifetime", 0) or 0
    by_strat = today_stats.get("by_strategy") or {}
    today_count = (by_strat.get(strategy_name) or {}).get("trades_lifetime", 0) or 0
    return max(state_count, today_count)

