class TestResolveLifetimeTrades(unittest.TestCase):
    def test_returns_state_when_today_empty_weekend_case(self):
        """Reproduces 2026-05-24: state=1 trade, by_strategy={} on Sunday."""
        state = {"strategies": {"options-momentum": {"trades_lifetime": 1}}}
        result = _resolve_lifetime_trades("options-momentum", {"by_strategy": {}}, state)
        self.assertEqual(result, 1)

    def test_returns_zero_when_genuinely_no_trades(self):
        state = {"strategies": {"new-strat": {"trades_lifetime": 0}}}
        result = _resolve_lifetime_trades("new-strat", {"by_strategy": {}}, state)
        self.assertEqual(result, 0)

    def test_returns_max_when_today_higher(self):
        state = {"strategies": {"s": {"trades_lifetime": 3}}}
        today = {"by_strategy": {"s": {"trades_lifetime": 5}}}
        result = _resolve_lifetime_trades("s", today, state)
        self.assertEqual(result, 5)

    def test_handles_none_by_strategy(self):
        state = {"strategies": {"s": {"trades_lifetime": 2}}}
        result = _resolve_lifetime_trades("s", {"by_strategy": None}, state)
        self.assertEqual(result, 2)

    def test_strategy_missing_from_state(self):
        result = _resolve_lifetime_trades("unknown", {"by_strategy": {}}, {})
        self.assertEqual(result, 0)
